patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 0632f3cfc6dd..f60d56a02b27 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3307,6 +3307,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       Value *Arg = II->getArgOperand(0);
       Value *Vect;

+
       if (Value *NewOp =
               simplifyReductionOperand(Arg, /*CanReorderLanes=*/true)) {
         replaceUse(II->getOperandUse(0), NewOp);
@@ -3480,6 +3481,24 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   //  * The select condition is not a vector, or the intrinsic does not
   //    perform cross-lane operations.
   switch (IID) {
+  case Intrinsic::ldexp: {
+    // ldexp(x, zext(i1 %cond)) -> x * select(%cond, 2.0, 1.0)
+    // ldexp(x, sext(i1 %cond)) -> x * select(%cond, 0.5, 1.0)
+    Value *X = II->getArgOperand(0);
+    Value *Exp = II->getArgOperand(1);
+    Value *Cond;
+    bool IsZExt = match(Exp, m_ZExt(m_Value(Cond)));
+    bool IsSExt = !IsZExt && match(Exp, m_SExt(m_Value(Cond)));
+
+    if ((IsZExt || IsSExt) && Cond->getType()->isIntegerTy(1)) {
+      Constant *OnTrue = ConstantFP::get(X->getType(), IsZExt ? 2.0 : 0.5);
+      Constant *OnFalse = ConstantFP::get(X->getType(), 1.0);
+      Value *Select = Builder.CreateSelect(Cond, OnTrue, OnFalse);
+      Value *Mul = Builder.CreateFMulFMF(X, Select, II);
+      return replaceInstUsesWith(CI, Mul);
+    }
+    [[fallthrough]];
+  }
   case Intrinsic::ctlz:
   case Intrinsic::cttz:
   case Intrinsic::ctpop:
@@ -3508,6 +3527,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

+
 // Fence instruction simplification
 Instruction *InstCombinerImpl::visitFenceInst(FenceInst &FI) {
   auto *NFI = dyn_cast<FenceInst>(FI.getNextNonDebugInstruction());
